/* adm-master-acxct-sql-oracle.xml selectAcxct */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT A.* FROM ( SELECT A.REPACKEY ,(SELECT ACNM FROM TADMIN_MST_AC AC WHERE AC.OWKEY = A.OWKEY AND AC.ACKEY = A.REPACKEY) REPACNM ,A.ACKEY ,A.ACNM ,A.ZIPCD ,A.ADDR1 ,A.ADDR2 ,A.INSERTDATE ,A.UPDATEDATE ,A.INSERTURKEY ,A.UPDATEURKEY ,A.DELYN ,A.REPACTYPE ,'REP_ACTYPE' ||';'|| A.REPACTYPE AS REP_ACTYPE_DESC ,A.ASNUSEYN ,A.OWKEY ,(SELECT OWNM FROM TADMIN_MST_OW OW WHERE OW.OWKEY = A.OWKEY) OWNM ,'YESORNO' ||';'|| A.DELYN AS DELYN_DESC ,'YESORNO' ||';'|| A.ASNUSEYN AS ASNUSEYN_DESC FROM TADMIN_MST_AC A ) A
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY A.UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.update:
/* adm-master-acxct-sql-oracle.xml - updateTAdminMstAcxct */
UPDATE  TADMIN_MST_ACXCT
SET 
	  URKEY               = #{urkey}
	, URNM                = #{urnm}
	, STOREORDTYPE        = #{storeordtype}
	, ACICGRTYPE          = #{acicgrtype}
	, ETCACICGRTYPE       = #{etcacicgrtype}
	, NEWYN               = #{newyn}
	, ACXCTTEL1           = #{acxcttel1}
	, ACXCTTEL2           = #{acxcttel2}
	, POORDTYPE           = #{poordtype}
	, BHAULINGYN          = #{bhaulingyn}
	, LDGTM               = #{ldgtm}
	, UNLDGTM             = #{unldgtm}
	, POLEADTM            = #{poleadtm}
	, PODDLNTIME          = #{poddlntime}
	, CARPLT              = #{carplt}
	, UPDATEDATE   		  = #{sysdate}
	, UPDATEURKEY  		  = #{surkey}
WHERE  
	ACKEY = #{ackey}
	AND OWKEY = #{owkey}
	AND CTKEY = #{ctkey}
	AND RNDKEY = #{rndkey}
	AND ICGRPKEY = #{icgrpkey}

/* adm-master-acxct-sql-oracle.xml - updateTWorkMstAcxct */
UPDATE  TWORK_MST_AC
SET 
	  URKEY               = #{urkey}
	, URNAME              = #{urname}
	, STOREORDTYPE        = #{storeordtype}
	, ACICGRTYPE          = #{acicgrtype}
	, ETC_ACICGRTYPE      = #{etc_acicgrtype}
	, NEWYN               = #{newyn}
	, POORDTYPE           = #{poordtype}
	, BHAULINGYN          = #{bhaulingyn}
	, LDG_TIME            = #{ldg_time}
	, UNLDG_TIME          = #{unldg_time}
	, POLEADTM            = #{poleadtm}
	, POCLOSDATE          = #{poclosdate}
	, UPDATEDATE   		  = #{sysdate}
	, UPDATEURKEY  		  = #{surkey}
WHERE  
ACKEY = #{ackey}
AND CTKEY = #{ctkey}
AND OWKEY = #{owkey}

mapper.delete:
/* adm-master-acxct-sql-oracle.xml - deleteTAdminMstAcxct */
UPDATE  TADMIN_MST_ACXCT
SET      DELYN 				= 'Y'
	, UPDATEDATE   		  = #{sysdate}
	, UPDATEURKEY  		  = #{surkey}

WHERE  
	ACKEY = #{ackey}
	AND OWKEY = #{owkey}
	AND CTKEY = #{ctkey}
	AND RNDKEY = #{rndkey}
	AND ICGRPKEY = #{icgrpkey}
